        private async Task OnComparerChangedAsync(ParameterChangedEventArgs<IEqualityComparer<T?>?> arg)
        {
            // Apply comparer and refresh selected values
            _selectedValues = new HashSet<T?>(_selectedValues, arg.Value);
            await UpdateSelectedValuesStateAsync(arg.Value);
        }

        private async Task OnSelectedValuesChangedAsync(ParameterChangedEventArgs<IReadOnlyCollection<T?>?> arg)
        {
            var value = arg.Value;

            // Update internal HashSet with new values - make a defensive copy to avoid shared references
            // The HashSet uses the Comparer for equality checks and ensures uniqueness
            _selectedValues = value != null ? new HashSet<T?>(value, Comparer) : new HashSet<T?>(Comparer);

            // Notify all subscribed items of the selection change
            await _context.NotifySelectionChangedAsync();

            if (!MultiSelection)
            {
                await SetValueAndUpdateTextAsync(_selectedValues.FirstOrDefault());
            }
            else
            {
                //Warning. Here the Converter was not set yet
                if (MultiSelectionTextFunc != null)
                {
                    await SetCustomizedTextAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)),
                        selectedConvertedValues: _selectedValues.Select(ConvertSet).ToList(),
                        multiSelectionTextFunc: MultiSelectionTextFunc);
                }
                else
                {
                    await SetTextAndUpdateValueAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)), updateValue: false);
                }
            }

            // Only fire FieldChanged after the first render to avoid triggering during initialization
            if (HasRendered)
            {
                FieldChanged(_selectedValues);
            }

            if (MultiSelection && typeof(T) == typeof(string))
            {
                await SetValueAndUpdateTextAsync((T?)(object?)ReadText, updateText: false);
            }
        }

        internal void UpdateFitContent()
        {
            if (FitContent)
            {
                var longestItemLength = 0;
                var longestItem = default(MudSelectItem<T>);
                foreach (var item in _context.ShadowItems)
                {
                    var value = item.Value;
                    var valueToString = ConvertSet(value);
                    var length = valueToString?.Length ?? 0;

                    if (length > longestItemLength)
                    {
                        longestItem = item;
                        longestItemLength = length;
                    }
                }

                if (ReferenceEquals(_longestItem, longestItem))
                {
                    return;
                }

                _longestItem = longestItem;
                StateHasChanged();
                return;
            }

            _longestItem = null;
        }

        internal void InvalidateFitContent()
        {
            if (FitContent)
            {
                _needsFitContentRefresh = true;
            }
        }

        private void OnFitContentChanged(ParameterChangedEventArgs<bool> args)
        {
            if (args.Value)
            {
                UpdateFitContent();
                return;
            }

            _needsFitContentRefresh = false;
            _longestItem = null;
        }

        private void UpdateIcon()
        {
            if (!string.IsNullOrWhiteSpace(AdornmentIcon))
            {
                _currentIcon = AdornmentIcon;
                return;
            }

            _currentIcon = _openState.Value ? CloseIcon : OpenIcon;
        }

        private Task HighlightItemForValueAsync(T? value)
        {
            _context.TryGetItemByValue(value, out var item);
            return HighlightItemAsync(item);
        }

        private Task HighlightItemAsync(MudSelectItem<T>? item)
        {
            _activeItemId = item?.ItemId;
            return InvokeAsync(StateHasChanged);
        }

        private void UpdateSelectAllChecked()
        {
            if (MultiSelection && SelectAll)
            {
                if (_selectedValues.Count == 0)
                {
                    _selectAllChecked = false;
                }
                else if (Items.Count(x => !x.Disabled) == _selectedValues.Count)
                {
                    _selectAllChecked = true;
                }
                else
                {
                    _selectAllChecked = null;
                }
            }
        }

        private async Task SelectAllClickAsync()
        {
            // Manage the fake tri-state of a checkbox
            if (!_selectAllChecked.HasValue)
            {
                _selectAllChecked = true;
            }
            else if (_selectAllChecked.Value)
            {
                _selectAllChecked = false;
            }
            else
            {
                _selectAllChecked = true;
            }

            // Define the items selection
            if (_selectAllChecked.Value)
            {
                await SelectAllItems();
            }
            else
            {
                await ClearAsync();
            }
        }

        private async Task SelectAllItems()
        {
            if (!MultiSelection)
            {
                return;
            }

            var selectedValues = new HashSet<T?>(Items.Where(x => !x.Disabled && x.Value != null).Select(x => x.Value), Comparer);
            _selectedValues = new HashSet<T?>(selectedValues, Comparer);

            if (MultiSelectionTextFunc != null)
            {
                await SetCustomizedTextAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)),
                    selectedConvertedValues: _selectedValues.Select(ConvertSet).ToList(),
                    multiSelectionTextFunc: MultiSelectionTextFunc);
            }
            else
            {
                await SetTextAndUpdateValueAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)), updateValue: false);
            }

            UpdateSelectAllChecked();
            _selectedValues = selectedValues; // need to force selected values because Blazor overwrites it under certain circumstances due to changes of Text or Value
            await BeginValidateAsync();
            await UpdateSelectedValuesStateAsync();
            FieldChanged(_selectedValues);

            if (MultiSelection && typeof(T) == typeof(string))
            {
                SetValueAndUpdateTextAsync((T?)(object?)ReadText, updateText: false).CatchAndLog();
            }
        }

        private async Task OnFocusOutAsync()
        {
            if (_openState.Value)
            {
                // when the menu is open we immediately get back the focus if we lose it (i.e. because of checkboxes in multi-select)
                // otherwise we can't receive key strokes any longer
                await FocusAsync();
            }
        }

        private Task SelectNextItem() => SelectAdjacentItem(+1);

        private Task SelectPreviousItem() => SelectAdjacentItem(-1);

        private async Task SelectAdjacentItem(int direction)
        {
            if (Items.Count == 0)
            {
                return;
            }

            var index = Items.FindIndex(x => x.ItemId == _activeItemId);
            if (direction < 0 && index < 0)
            {
                index = 0;
            }

            MudSelectItem<T>? item = null;
            // the loop allows us to jump over disabled items until we reach the next non-disabled one
            for (var i = 0; i < Items.Count; i++)
            {
                index += direction;
                if (index < 0)
                {
                    index = 0;
                }

                if (index >= Items.Count)
                {
                    index = Items.Count - 1;
                }

                if (Items[index].Disabled)
                {
                    continue;
                }

                item = Items[index];
                if (!MultiSelection)
                {
                    // When SelectionOnEnter is true, we only update the visual highlight during navigation.
                    // When false (default), the value is immediately updated as the user moves through the list.
                    if (!SelectionOnEnter)
                    {
                        _selectedValues.Clear();
                        _selectedValues.Add(item.Value);
                        await SetValueAndUpdateTextAsync(item.Value, updateText: true);
                    }

                    await HighlightItemAsync(item);
                    break;
                }

                // in multiselect mode don't select anything, just highlight.
                // selecting is done by Enter
                await HighlightItemAsync(item);
                break;
            }

            await _elementReference.SetText(ReadText);
            await ScrollToItemAsync(item);
        }

        private ValueTask ScrollToItemAsync(MudSelectItem<T>? item)
            => item != null ? ScrollManager.ScrollToListItemAsync(item.ItemId) : ValueTask.CompletedTask;

        private async Task SelectFirstItem(string? startChar = null)
        {
            IReadOnlyCollection<MudSelectItem<T>> selectList = Items;

            if (!_openState.Value)
            {
                // When closed, use shadow lookup to include all items (visible + hidden)
                selectList = _context.ShadowItems;
            }

            if (selectList.Count == 0)
            {
                return;
            }

            if (!string.IsNullOrWhiteSpace(startChar))
            {
                // SelectItemBySearch handles disabled items
                var searchItem = SelectItemBySearch(selectList, startChar);
                if (searchItem is not null)
                {
                    await SelectAndHighlightItemAsync(searchItem);
                    return;
                }
            }

            // Find first non-disabled item
            foreach (var item in selectList)
            {
                if (item.Disabled)
                {
                    continue;
                }

                await SelectAndHighlightItemAsync(item);
                return;
            }
        }

        private MudSelectItem<T>? SelectItemBySearch(IReadOnlyCollection<MudSelectItem<T>> items, string inputChar)
        {
            UpdateSearchText(inputChar);

            MudSelectItem<T>? activeItem = null;
            MudSelectItem<T>? previousItem = null;
            MudSelectItem<T>? firstMatch = null;
            MudSelectItem<T>? nextMatch = null;
            var foundPrevious = false;

            foreach (var item in items)
            {
                TrackSpecialItems(item, ref activeItem, ref previousItem);

                if (IsMatch(item))
                {
                    firstMatch ??= item;

                    if (foundPrevious)
                    {
                        nextMatch ??= item;
                    }

                    if (item == previousItem)
                    {
                        foundPrevious = true;
                    }
                }
            }

            return DetermineResult(activeItem, previousItem, firstMatch, nextMatch);

            void UpdateSearchText(string input)
            {
                var now = TimeProvider.GetUtcNow();

                if (now - _lastSearchTime > QuickSearchInterval)
                {
                    _lastSelectedId = _activeItemId;
                    _searchText = input;
                }
                else
                {
                    _searchText += input;
                }

                _lastSearchTime = now;
            }

            void TrackSpecialItems(MudSelectItem<T> item, ref MudSelectItem<T>? active, ref MudSelectItem<T>? previous)
            {
                if (item.ItemId == _activeItemId)
                {
                    active = item;
                }

                if (item.ItemId == _lastSelectedId)
                {
                    previous = item;
                }
            }

            bool IsMatch(MudSelectItem<T> item)
            {
                if (item.Disabled)
                {
                    return false;
                }

                var text = ConvertSet(item.Value);
                return text is not null && text.StartsWith(_searchText, StringComparison.InvariantCultureIgnoreCase);
            }

            MudSelectItem<T>? DetermineResult(MudSelectItem<T>? active, MudSelectItem<T>? previous,
                                               MudSelectItem<T>? first, MudSelectItem<T>? next)
            {
                if (first is null)
                {
                    return active;
                }

                if (previous is null)
                {
                    return first;
                }

                return next ?? first;
            }
        }

        private async Task SelectAndHighlightItemAsync(MudSelectItem<T> item)
        {
            if (!MultiSelection)
            {
                _selectedValues.Clear();
                _selectedValues.Add(item.Value);
                await SetValueAndUpdateTextAsync(item.Value, updateText: true);
                await UpdateSelectedValuesStateAsync();
            }

            await HighlightItemAsync(item);
            await _elementReference.SetText(ReadText);
            await ScrollToItemAsync(item);
        }

        private async Task SelectLastItem()
        {
            if (Items.Count == 0)
            {
                return;
            }

            var item = Items.LastOrDefault(x => !x.Disabled);
            if (item == null)
            {
                return;
            }

            if (!MultiSelection)
            {
                _selectedValues.Clear();
                _selectedValues.Add(item.Value);
                await SetValueAndUpdateTextAsync(item.Value, updateText: true);
            }

            await HighlightItemAsync(item);
            await _elementReference.SetText(ReadText);
            await ScrollToItemAsync(item);
        }

        internal Task HandleMouseDown(MouseEventArgs args)
        {
            if (args.Button != 0) // if it wasn't left click drop out
            {
                return Task.CompletedTask;
            }

            return ToggleMenu();
        }

        /// <summary>
        /// Internal method for MudSelectItem to access the converted string value.
        /// </summary>
        internal string? ConvertValueToString(T? value) => ConvertSet(value);

        /// <summary>
        /// Internal method for the context to access the current selected values.
        /// </summary>
        internal IReadOnlyCollection<T?>? GetSelectedValues() => _selectedValuesState.Value;

        private bool CanHandleKeys() => !GetDisabledState() && !GetReadOnlyState();

        private async Task HandleArrowUpAsync(KeyboardEventArgs args)
        {
            if (args.AltKey)
            {
                await CloseMenu();
                return;
            }

            if (!_openState.Value)
            {
                await OpenMenu();
                return;
            }

            await SelectPreviousItem();
        }

        private async Task HandleArrowDownAsync(KeyboardEventArgs args)
        {
            if (args.AltKey)
            {
                await OpenMenu();
                return;
            }

            if (!_openState.Value)
            {
                await OpenMenu();
                return;
            }

            await SelectNextItem();
        }

        private async Task HandleEnterAsync()
        {
            var index = Items.FindIndex(x => x.ItemId == _activeItemId);
            if (!MultiSelection)
            {
                if (!_openState.Value)
                {
                    await OpenMenu();
                    return;
                }

                // this also closes the menu
                await SelectOption(index);
                return;
            }

            if (!_openState.Value)
            {
                await OpenMenu();
                return;
            }

            await SelectOption(index);
            await _elementReference.SetText(ReadText);
        }

        private async Task HandleKeyAAsync(KeyboardEventArgs args)
        {
            if (args.CtrlKey)
            {
                if (MultiSelection)
                {
                    await SelectAllClickAsync();
                    StateHasChanged();
                }
            }
            else if (!args.ShiftKey && !args.AltKey && !args.MetaKey)
            {
                await SelectFirstItem(args.Key.ToLowerInvariant());
                await FocusAsync();
            }
        }

        private async Task HandleCharacterSearchAsync(KeyboardEventArgs args)
        {
            if (args.CtrlKey || args.ShiftKey || args.AltKey || args.MetaKey)
            {
                return;
            }

            var key = args.Key;
            if (string.IsNullOrWhiteSpace(key))
            {
                return;
            }

            key = key.ToLowerInvariant();
            if (key.Length != 1)
            {
                return;
            }

            await SelectFirstItem(key);
            await FocusAsync();
        }

        internal Task OnBlurAsync(FocusEventArgs obj)
        {
            return base.OnBlur.InvokeAsync(obj);
        }

        protected override void OnInitialized()
        {
            base.OnInitialized();
            UpdateIcon();
        }

        protected override void OnParametersSet()
        {
            base.OnParametersSet();
            UpdateIcon();
        }

        protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            if (firstRender)
            {
                var options = new KeyInterceptorOptions(
                    "mud-input-control",
                    [
                        // prevent scrolling page, toggle open/close
                        new(" ", preventDown: "key+none"),
                        // prevent scrolling page, instead highlight previous item
                        new("ArrowUp", preventDown: "key+none"),
                        // prevent scrolling page, instead highlight next item
                        new("ArrowDown", preventDown: "key+none"),
                        new("Home", preventDown: "key+none"),
                        new("End", preventDown: "key+none"),
                        new("Escape"),
                        new("Enter", preventDown: "key+none"),
                        new("NumpadEnter", preventDown: "key+none"),
                        // select all items instead of all page text
                        new("a", preventDown: "key+ctrl"),
                        // select all items instead of all page text
                        new("A", preventDown: "key+ctrl"),
                        // for our users
                        new("/./", subscribeDown: true, subscribeUp: true)
                    ]);

                await KeyInterceptorService.SubscribeAsync(ElementId, options, keys => keys
                    .HookKeyUp(args => OnKeyUp.InvokeAsync(args))
                    .When(CanHandleKeys, builder => builder
                        .HookKeyDown(args => OnKeyDown.InvokeAsync(args))
                        .OnKeyDown("Tab", () => CloseMenu(false))
                        .OnKeyDown("ArrowUp", HandleArrowUpAsync)
                        .OnKeyDown("ArrowDown", HandleArrowDownAsync)
                        .OnKeyDown(" ", ToggleMenu)
                        .OnKeyDown("Escape", () => CloseMenu(true))
                        .OnKeyDown("Home", () => SelectFirstItem())
                        .OnKeyDown("End", SelectLastItem)
                        .OnKeyDownAny(["Enter", "NumpadEnter"], HandleEnterAsync)
                        .OnKeyDownAny(["a", "A"], HandleKeyAAsync)
                        .OnKeyDown("/^[^ ]$/", HandleCharacterSearchAsync)));
            }

            await base.OnAfterRenderAsync(firstRender);

            var needsFitContentRefresh = _needsFitContentRefresh;
            _needsFitContentRefresh = false;

            if (needsFitContentRefresh)
            {
                UpdateFitContent();
            }
            else if (firstRender)
            {
                // we need to render the initial Value which is not possible without the items
                // which supply the RenderFragment. So in this case, a second render is necessary
                StateHasChanged();
            }

            UpdateSelectAllChecked();

            // Highlight after items are fully rendered
            if (_needsHighlightAfterRender)
            {
                _needsHighlightAfterRender = false;
                await InvokeAsync(async () =>
                {
                    if (MultiSelection)
                    {
                        var firstNonDisabled = Items.FirstOrDefault(x => !x.Disabled);
                        await HighlightItemAsync(firstNonDisabled);
                    }
                    else
                    {
                        await HighlightItemForValueAsync(ReadValue);
                    }
                });
            }
        }

        /// <summary>
        /// Gets the resolved modal overlay value, using the global default from <see cref="PopoverOptions"/> if not explicitly set.
        /// </summary>
        protected bool GetModal() => Modal ?? PopoverService.PopoverOptions.ModalOverlay;

        protected RenderFragment? GetSelectedValuePresenter()
        {
            if (!_context.TryGetShadowItemByValue(ReadValue, out var item))
            {
                return null; //<-- for now. we'll add a custom template to present values (set from outside) which are not on the list?
            }

            return item.ChildContent;
        }

        /// <summary>
        /// Occurs when the <c>Clear</c> button has been clicked.
        /// </summary>
        /// <remarks>
        /// This is the first event raised when the clear button is clicked.
        /// The <see cref="SelectedValues"/> are cleared and the <see cref="OnClearButtonClick"/> event is raised.
        /// </remarks>
        protected async ValueTask SelectClearButtonClickHandlerAsync(MouseEventArgs e)
        {
            await SetValueAndUpdateTextAsync(default, false);
            await SetTextAndUpdateValueAsync(null, false);
            _selectedValues.Clear();
            await BeginValidateAsync();
            StateHasChanged();
            await UpdateSelectedValuesStateAsync();
            FieldChanged(_selectedValues);
            await OnClearButtonClick.InvokeAsync(e);
        }

        private async Task UpdateSelectedValuesStateAsync(IEqualityComparer<T?>? comparer = null)
        {
            await _selectedValuesState.SetValueAsync(new HashSet<T?>(_selectedValues, comparer ?? Comparer));
            await _context.NotifySelectionChangedAsync();
        }

        protected async Task SetCustomizedTextAsync(string text, bool updateValue = true,
            IReadOnlyList<string?>? selectedConvertedValues = null,
            Func<IReadOnlyList<string?>?, string>? multiSelectionTextFunc = null)
        {
            // The Text property of the control is updated
            var customText = multiSelectionTextFunc?.Invoke(selectedConvertedValues);
            await SetTextCoreAsync(customText);

            // The comparison is made on the multiSelectionText variable
            if (_multiSelectionText != text)
            {
                _multiSelectionText = text;
                if (!string.IsNullOrWhiteSpace(_multiSelectionText))
                {
                    Touched = true;
                }

                if (updateValue)
                {
                    await UpdateValuePropertyAsync(false);
                }
            }
        }

        /// <remarks>
        /// If <see cref="ToStringFunc"/> is set, it is used to convert the value to a string; otherwise, the base implementation is used.
        /// </remarks>
        /// <inheritdoc />
        protected override string? ConvertSet(T? input)
        {
            return ToStringFunc is not null
                ? ToStringFunc(input)
                : base.ConvertSet(input);
        }

        protected override Task UpdateValuePropertyAsync(bool updateText)
        {
            // For MultiSelection of non-string T's we don't update the Value!!!
            if (typeof(T) == typeof(string) || !MultiSelection)
            {
                base.UpdateValuePropertyAsync(updateText);
            }

            return Task.CompletedTask;
        }

        protected override Task UpdateTextPropertyAsync(bool updateValue)
        {
            // when multiselection is true, we return
            // a comma separated list of selected values
            if (MultiSelectionTextFunc != null)
            {
                return MultiSelection
                    ? SetCustomizedTextAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)),
                        selectedConvertedValues: _selectedValues.Select(ConvertSet).ToList(),
                        multiSelectionTextFunc: MultiSelectionTextFunc)
                    : base.UpdateTextPropertyAsync(updateValue);
            }

            return MultiSelection
                ? SetTextAndUpdateValueAsync(string.Join(Delimiter, _selectedValues.Select(ConvertSet)))
                : base.UpdateTextPropertyAsync(updateValue);
        }

        /// <summary>
        /// Clears all selections and resets validation
        /// </summary>
        /// <remarks>
        /// To maintain validation errors (e.g. required), use <see cref="ClearAsync"/>
        /// </remarks>
        protected override async Task ResetValueAsync()
        {
            await ClearAsync();
            await base.ResetValueAsync();
        }

        /// <summary>
        /// Gets whether the value is currently selected.
        /// </summary>
        /// <param name="value">The value to test.</param>
        /// <returns>When <c>true</c>, the specified value exists in <see cref="SelectedValues"/>.</returns>
        protected override bool HasValue(T? value)
        {
            // Fixes issue #4328
            if (MultiSelection)
            {
                return _selectedValues.Count != 0;
            }

            return base.HasValue(value);
        }

        /// <inheritdoc />
        protected override async ValueTask DisposeAsyncCore()
        {
            await base.DisposeAsyncCore();

            if (IsJSRuntimeAvailable)
            {
                await KeyInterceptorService.UnsubscribeAsync(ElementId);
            }
        }
    }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Web;
using Microsoft.JSInterop;
using MudBlazor.State;

namespace MudBlazor
{
    /// <summary>
    /// Represents a base class for designing form input components.
    /// </summary>
    /// <typeparam name="T">The type of item being input.</typeparam>
    public abstract class MudBaseInput<T> : MudFormComponent<T, string>
    {
        private bool _isDirty;
        /// <summary>
        /// Prevents validation from occurring more than once during a validation cycle.
        /// </summary>
        /// <remarks>
        /// This field is set to <c>true</c> to prevent validation from occurring more than once during a validation cycle.  Each change in the <see cref="Value"/> will reset this field to <c>false</c>.
        /// </remarks>
        private bool _validated;
        protected bool _isFocused;
        protected bool _forceTextUpdate;

        /// <summary>
        /// The resolved input element ID.
        /// </summary>
        protected string? InputElementId => _inputIdState.Value;
        private string? _userAttributesId = Identifier.Create("mudinput");
        private readonly string _componentId = Identifier.Create("mudinput");
        private readonly ParameterState<string?> _textState;
        private readonly ParameterState<T?> _valueState;
        private readonly ParameterState<string?> _formatState;
        private readonly ParameterState<string?> _inputIdState;

        protected MudBaseInput()
        {
            using var registerScope = CreateRegisterScope();
            _textState = registerScope.RegisterParameter<string?>(nameof(Text))
                .WithParameter(() => Text)
                .WithEventCallback(() => TextChanged)
                .WithChangeHandler(OnTextParameterChangedAsync);
            _valueState = registerScope.RegisterParameter<T?>(nameof(Value))
                .WithParameter(() => Value)
                .WithEventCallback(() => ValueChanged)
                .WithChangeHandler(OnValueParameterChangedAsync);
            _formatState = registerScope.RegisterParameter<string?>(nameof(Format))
                .WithParameter(() => Format)
                .WithChangeHandler(OnCultureAndFormatChangedAsync);
            _inputIdState = registerScope.RegisterParameter<string?>(nameof(InputId))
                .WithParameter(() => InputId)
                .WithChangeHandler(UpdateInputIdStateAsync);
        }

        [Inject]
        private IJSRuntime JsRuntime { get; set; } = null!;

        /// <summary>
        /// Allows the component to receive input.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool Disabled { get; set; }

        [CascadingParameter(Name = "ParentDisabled")]
        private bool ParentDisabled { get; set; }

        /// <summary>
        /// Prevents the input from being changed by the user.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.  When <c>true</c>, the user can copy text in the control, but cannot change the <see cref="Value" />.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool ReadOnly { get; set; }

        [CascadingParameter(Name = "ParentReadOnly")]
        private bool ParentReadOnly { get; set; }

        /// <summary>
        /// Fills the full width of the parent container.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public bool FullWidth { get; set; }

        /// <summary>
        /// Changes the <see cref="Value"/> as soon as input is received.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.  When <c>true</c>, the <see cref="Value"/> property will be updated any time user input occurs.  Otherwise, <see cref="Value"/> is updated when the user presses <c>Enter</c> or the input loses focus.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool Immediate { get; set; }

        /// <summary>
        /// Displays an underline for the input.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>true</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public bool Underline { get; set; } = true;

        /// <summary>
        /// The ID of the helper element, for use by <c>aria-describedby</c>.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.  When set it is appended to the <c>aria-describedby</c> attribute to improve accessibility for users. This ID takes precedence over the helper element rendered when <see cref="HelperText"/> is provided.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public string? HelperId { get; set; }

        /// <summary>
        /// The text displayed below the text field.
        /// </summary>
        /// <remarks>
        /// This property is typically used to help the user understand what kind of input is allowed.  The <see cref="HelperTextOnFocus"/> property controls when this text is visible.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? HelperText { get; set; }

        /// <summary>
        /// Displays the <see cref="HelperText"/> only when this input has focus.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool HelperTextOnFocus { get; set; }

        /// <summary>
        /// The icon displayed for the adornment.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.  This icon will be displayed when <see cref="Adornment"/> is <c>Start</c> or <c>End</c>, and no value for <see cref="AdornmentText"/> is set.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? AdornmentIcon { get; set; }

        /// <summary>
        /// The text displayed for the adornment.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.  This text will be displayed when <see cref="Adornment"/> is <c>Start</c> or <c>End</c>.  The <see cref="AdornmentIcon"/> property will be ignored if this property is set.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? AdornmentText { get; set; }

        /// <summary>
        /// The location of the adornment icon or text.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Adornment.None"/>.  When set to <c>Start</c> or <c>End</c>, the <see cref="AdornmentText"/> will be displayed, or <see cref="AdornmentIcon"/> if no adornment text is specified.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public Adornment Adornment { get; set; } = Adornment.None;

        /// <summary>
        /// Limits validation to when the user changes the <see cref="Value"/>.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>. When <c>true</c>, validation only occurs if the user has changed the input value at least once.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool OnlyValidateIfDirty { get; set; }

        /// <summary>
        /// The color of <see cref="AdornmentText"/> or <see cref="AdornmentIcon"/>.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Color.Default"/>.  Theme colors are supported.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public Color AdornmentColor { get; set; } = Color.Default;

        /// <summary>
        /// The <c>aria-label</c> for the adornment.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public string? AdornmentAriaLabel { get; set; }

        /// <summary>
        /// The size of the icon.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Size.Medium"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public Size IconSize { get; set; } = Size.Medium;

        /// <summary>
        /// Occurs when the adornment icon (but not the text) has been clicked.
        /// </summary>
        [Parameter]
        public EventCallback<MouseEventArgs> OnAdornmentClick { get; set; }

        /// <summary>
        /// The appearance variation to use.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Variant.Text"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public Variant Variant { get; set; } = Variant.Text;

        /// <summary>
        /// The amount of vertical spacing for this input.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="Margin.None"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public Margin Margin { get; set; } = Margin.None;

        /// <summary>
        /// Typography for the input text.
        /// </summary>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public Typo Typo { get; set; } = Typo.subtitle1;

        /// <summary>
        /// The text displayed in the input if no <see cref="Value"/> is specified.
        /// </summary>
        /// <remarks>
        /// This property is typically used to give the user a hint as to what kind of input is expected.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? Placeholder { get; set; }

        /// <summary>
        /// The optional character count and stop count.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.  When <c>0</c>, the current character count is displayed.  When <c>1</c> or greater, the character count and this count are displayed.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public int? Counter { get; set; }

        /// <summary>
        /// The maximum number of characters allowed.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>524288</c>.  This value is typically set to a maximum length such as the size of a database column the value will be persisted to.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public int MaxLength { get; set; } = 524288;

        /// <summary>
        /// The label for this input.
        /// </summary>
        /// <remarks>
        /// If no <see cref="Value"/> is specified, the label will be displayed in the input.  Otherwise, it will be scaled down to the top of the input.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? Label { get; set; }

        /// <summary>
        /// Automatically receives focus.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.  When <c>true</c>, the input will receive focus automatically.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool AutoFocus { get; set; }

        /// <summary>
        ///  A multiline input (textarea) will be shown, if set to more than one line.
        /// </summary>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public int Lines { get; set; } = 1;

        /// <summary>
        /// The text displayed in the input.
        /// </summary>
        [Parameter, ParameterState]
        [Category(CategoryTypes.FormComponent.Data)]
        public string? Text { get; set; }

        /// <summary>
        /// The type of input expected.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="InputMode.text"/>.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public virtual InputMode InputMode { get; set; } = InputMode.text;

        /// <summary>
        /// The regular expression used to validate the <see cref="Value"/> property.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>null</c>.  This property is used to validate the input against a regular expression.  Not supported if <see cref="Lines"/> is <c>2</c> or greater.  Must be a valid JavaScript regular expression.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Validation)]
        public virtual string? Pattern { get; set; }

        /// <summary>
        /// Shows the label inside the input if no <see cref="Value"/> is specified.
        /// </summary>
        /// <remarks>
        /// Defaults to <c>false</c>.
        /// When <c>true</c>, the label will not move into the input when the input is empty.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Appearance)]
        public bool ShrinkLabel { get; set; }

        /// <summary>
        /// Occurs when the <see cref="Text"/> property has changed.
        /// </summary>
        [Parameter]
        public EventCallback<string?> TextChanged { get; set; }

        /// <summary>
        /// Occurs when the input loses focus.
        /// </summary>
        [Parameter]
        public EventCallback<FocusEventArgs> OnBlur { get; set; }

        /// <summary>
        /// Occurs when the internal text value has changed.
        /// </summary>
        [Parameter]
        public EventCallback<string?> OnInternalInputChanged { get; set; }

        /// <summary>
        /// Occurs when a key has been pressed down.
        /// </summary>
        [Parameter]
        public EventCallback<KeyboardEventArgs> OnKeyDown { get; set; }

        /// <summary>
        /// Allows the default key-down action to occur.
        /// </summary>
        /// <remarks>
        /// When <c>true</c>, the browser will not perform its default behavior when a key-down occurs.  This is typically used when a key-down needs to override a browser's default behavior.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool KeyDownPreventDefault { get; set; }

        /// <summary>
        /// Occurs when a pressed key has been released.
        /// </summary>
        [Parameter]
        public EventCallback<KeyboardEventArgs> OnKeyUp { get; set; }

        /// <summary>
        /// Prevents the default key-up action.
        /// </summary>
        /// <remarks>
        /// When <c>true</c>, the browser will not perform its default behavior when a key-up occurs.  This is typically used when a key-up needs to override the browser's default behavior.
        /// </remarks>
        [Parameter]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public bool KeyUpPreventDefault { get; set; }

        /// <summary>
        /// Occurs when the <see cref="Value"/> property has changed.
        /// </summary>
        [Parameter]
        public EventCallback<T?> ValueChanged { get; set; }

        /// <summary>
        /// The value for this input.
        /// </summary>
        /// <remarks>
        /// This property represents the strongly typed value for the input.  It is typically the result of parsing raw input via the <see cref="Text"/> property.
        /// </remarks>
        [Parameter, ParameterState]
        [Category(CategoryTypes.FormComponent.Data)]
        public T? Value { get; set; }

        /// <summary>
        /// The format applied to values.
        /// </summary>
        /// <remarks>
        /// This property is passed into the <c>ToString()</c> method of the <see cref="Value"/> property, such as formatting <c>int</c>, <c>float</c>, <c>DateTime</c> and <c>TimeSpan</c> values.
        /// </remarks>
        [Parameter, ParameterState]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? Format { get; set; }

        /// <summary>
        /// The ID of the input element.
        /// </summary>
        /// <remarks>
        /// When set takes precedence over any internally generated IDs.
        /// </remarks>
        [Parameter, ParameterState]
        [Category(CategoryTypes.FormComponent.Behavior)]
        public string? InputId { get; set; }

        protected bool GetDisabledState() => Disabled || ParentDisabled;

        protected bool GetReadOnlyState() => ReadOnly || ParentReadOnly;

        /// <summary>
        /// Occurs when the value has changed internally.
        /// </summary>
        /// <remarks>
        /// This method is called when the <see cref="Text"/> property needs to be refreshed from current <see cref="Value" />.
        /// </remarks>
        protected virtual Task UpdateTextPropertyAsync(bool updateValue)
        {
            return SetTextAndUpdateValueAsync(ConvertSet(ReadValue), updateValue);
        }

        /// <summary>
        /// When overridden, obtains focus for this input.
        /// </summary>
        /// <returns>A <see cref="ValueTask" /> object.</returns>
        public virtual ValueTask FocusAsync() => ValueTask.CompletedTask;

        /// <summary>
        /// When overridden, releases focus from this input.
        /// </summary>
        /// <returns>A <see cref="ValueTask" /> object.</returns>
        public virtual ValueTask BlurAsync() => ValueTask.CompletedTask;

        /// <summary>
        /// When overridden, selects this input.
        /// </summary>
        /// <returns>A <see cref="ValueTask" /> object.</returns>
        public virtual ValueTask SelectAsync() => ValueTask.CompletedTask;

        /// <summary>
        /// When overridden, selects a portion of the input.
        /// </summary>
        /// <param name="pos1">The index of the first character to select.</param>
        /// <param name="pos2">The index of the last character to select.</param>
        /// <returns>A <see cref="ValueTask" /> object.</returns>
        public virtual ValueTask SelectRangeAsync(int pos1, int pos2) => ValueTask.CompletedTask;

        protected internal virtual async Task OnBlurredAsync(FocusEventArgs obj)
        {
            _isFocused = false;

            if (ReadOnly)
            {
                return;
            }

            // all the OnBlur parents (TextField, MudMask, NumericField, DateRange, etc) currently point to this method
            // which causes this method to be fired repeatedly, we can use the obj.Type of FocusedEventArgs to track it

            if (!OnlyValidateIfDirty || _isDirty)
            {
                Touched = true;
                if (_validated)
                {
                    if (OnBlur.HasDelegate)
                    {
                        obj.Type += ".additional";
                        await OnBlur.InvokeAsync(obj);
                    }
                }
                else
                {
                    if (OnBlur.HasDelegate)
                    {
                        obj.Type += ".additional";
                        await BeginValidationAfterAsync(OnBlur.InvokeAsync(obj));
                    }
                    else
                    {
                        await ValidateValue();
                    }
                }
            }
        }

        protected virtual Task InvokeKeyDownAsync(KeyboardEventArgs obj)
        {
            _isFocused = true;

            return OnKeyDown.InvokeAsync(obj);
        }

        protected virtual Task InvokeKeyUpAsync(KeyboardEventArgs obj)
        {
            _isFocused = true;

            return OnKeyUp.InvokeAsync(obj);
        }

        protected virtual async Task SetValueAndUpdateTextAsync(T? value, bool updateText = true, bool force = false)
        {
            var valueChanged = !EqualityComparer<T?>.Default.Equals(ReadValue, value);

            if (!valueChanged && !force)
            {
                return;
            }

            _isDirty = true;
            _validated = false;

            // Use ParameterState to set Value instead of direct assignment
            // This ensures proper parameter lifecycle management
            await _valueState.SetValueAsync(value);

            // If force is true but value hasn't changed, ParameterState won't fire the callback
            // so we need to manually invoke it to maintain backward compatibility
            if (force && !valueChanged)
            {
                await ValueChanged.InvokeAsync(value);
            }

            if (updateText)
            {
                await UpdateTextPropertyAsync(false);
            }

            FieldChanged(value);
            await BeginValidateAsync();
        }

        private async Task OnValueParameterChangedAsync(ParameterChangedEventArgs<T?> arg)
        {
            _validated = false;
            var wasTouched = Touched;

            // When Value changes from parent, update Text from Value
            // But only if Text is not also being set in the same parameter update
            // Check ParameterView to see if Text is also present
            if (!arg.ParameterView.Contains<string?>(nameof(Text)))
            {
                // Always update text when Value changes (TextUpdateSuppression removed)
                _forceTextUpdate = false;
                await UpdateTextPropertyAsync(false);
            }

            // Notify the form that the field has changed and trigger re-validation
            // Only do this after the field has been touched.
            if (wasTouched)
            {
                FieldChanged(arg.Value);
                await BeginValidateAsync();
            }
        }

        /// <summary>
        /// Override to read Value from ParameterState instead of backing field.
        /// </summary>
        protected internal override T? ReadValue => _valueState.Value;

        /// <summary>
        /// Override to write Value to ParameterState instead of backing field.
        /// </summary>
        protected override Task SetValueCoreAsync(T? value) => _valueState.SetValueAsync(value);

        /// <summary>
        /// Occurs when the value has changed internally.
        /// </summary>
        /// <remarks>
        /// This method is called when the <see cref="Value"/> property needs to be refreshed from current <see cref="Text" />.
        /// </remarks>
        protected virtual Task UpdateValuePropertyAsync(bool updateText)
        {
            return SetValueAndUpdateTextAsync(ConvertGet(ReadText), updateText);
        }

        protected override string? GetFormat() => _formatState.Value;

        /// <inheritdoc />
        protected override IConverter<T?, string?> GetDefaultConverter()
        {
            return new DefaultConverter<T>
            {
                Culture = GetCulture,
                Format = GetFormat
            };
        }

        /// <inheritdoc />
        protected override async Task OnCultureAndFormatChangedAsync()
        {
            await base.OnCultureAndFormatChangedAsync();
            await UpdateTextPropertyAsync(false);
        }

        /// <inheritdoc />
        protected override async Task OnConverterChangedAsync()
        {
            await base.OnConverterChangedAsync();
            await UpdateTextPropertyAsync(false);
        }

        protected override async Task ValidateValue()
        {
            if (SubscribeToParentForm)
            {
                _validated = true;
                await base.ValidateValue();
            }
        }

        protected override async Task OnInitializedAsync()
        {
            await base.OnInitializedAsync();

            // Because the way the Value setter is built, it won't cause an update if the incoming Value is
            // equal to the initial value. This is why we force an update to the Text property here.
            if (typeof(T) != typeof(string) && string.IsNullOrWhiteSpace(ReadText))
            {
                await UpdateTextPropertyAsync(false);
            }

            if (Label == null && For != null)
            {
                Label = For.GetLabelString();
            }

            _userAttributesId = UserAttributes.FirstOrDefault(userAttribute => userAttribute.Key.Equals("id", StringComparison.InvariantCultureIgnoreCase)).Value?.ToString();

            if (_inputIdState.Value is null)
            {
                await UpdateInputIdStateAsync();
            }
        }

        /// <summary>
        /// Causes this input to be rerendered.
        /// </summary>
        /// <param name="forceTextUpdate">When <c>true</c>, the <see cref="Text"/> property will be updated before rendering.</param>
        public virtual void ForceRender(bool forceTextUpdate)
        {
            _forceTextUpdate = true;
            UpdateTextPropertyAsync(false).CatchAndLog();
            StateHasChanged();
        }

        /// <inheritdoc />
        public override async Task SetParametersAsync(ParameterView parameters)
        {
            var hasText = parameters.Contains<string>(nameof(Text));
            var hasValue = parameters.Contains<T>(nameof(Value));
            var currentValue = ReadValue;
            await base.SetParametersAsync(parameters);

            // Refresh Text from Value if Value is present but Text is not
            // This maintains backward compatibility with the old `if (hasValue && !hasText)` logic
            // ParameterState only fires OnValueParameterChangedAsync when value CHANGES,
            // but we need to update Text even when Value is passed unchanged (for formatting)
            if (hasValue && !hasText)
            {
                var valueChanged = !EqualityComparer<T?>.Default.Equals(currentValue, ReadValue);

                // Preserve in-progress user text across parent rerenders until Value actually changes.
                if (_isFocused && !valueChanged && !_forceTextUpdate)
                {
                    return;
                }

                // Always update text when Value changes (TextUpdateSuppression removed)
                _forceTextUpdate = false;
                await UpdateTextPropertyAsync(false);
            }
        }

        /// <inheritdoc />
        protected override async Task OnAfterRenderAsync(bool firstRender)
        {
            //Only focus automatically after the first render cycle!
            if (firstRender && AutoFocus)
            {
                await FocusAsync();
            }

            await base.OnAfterRenderAsync(firstRender);
        }

        /// <inheritdoc />
        protected override void OnParametersSet()
        {
            if (SubscribeToParentForm)
            {
                base.OnParametersSet();
            }
            else
            {
                // MudBlazor uses an unconventional SubscribeToParentForm mechanism whose behavior is not fully understandable.
                // Because of this, we must manually call OnParametersSet on the ParameterContainer to ensure ParameterState fields update correctly.
                //
                // Without this manual call, scenarios involving inherited components can fall out of sync. For example:
                // - Component1 inherits a base component that defines a state parameter.
                // - Component2 also inherits that same base component, wraps Component1, and forwards its base parameters to Component1.
                // In this case, ParameterState will not remain properly synchronized since base.OnParametersSet is called conditionally.
                ParameterContainer.OnParametersSet();
            }
        }

        /// <inheritdoc />
        protected override async Task ResetValueAsync()
        {
            await SetTextAndUpdateValueAsync(null, updateValue: true);
            _isDirty = false;
            _validated = false;
            await base.ResetValueAsync();
        }

        protected string? GetHelperId()
        {
            if (HelperId is not null)
            {
                return HelperId;
            }

            // error text replaces helper text in MudInputControl, so if the user does not provide a custom helper id, we have no valid helper element
            if (HasErrors)
            {
                return null;
            }

            return HelperText is not null
                ? $"{_inputIdState.Value}-helper-text"
                : null;
        }

        protected string? GetAriaDescribedByString()
        {
            var errorId = HasErrors ? ErrorIdState.Value : null;
            var helperId = GetHelperId();

            return errorId is not null && helperId is not null
                ? $"{errorId} {helperId}"
                : errorId ?? helperId ?? null;
        }

        /// <summary>
        /// The type of input received by this component.
        /// </summary>
        /// <remarks>
        /// Defaults to <see cref="InputType.Text"/>.
        /// </remarks>
        protected internal virtual InputType GetInputType() => InputType.Text;

        protected internal string? ReadText => _textState.Value;

        protected Task SetTextCoreAsync(string? text) => _textState.SetValueAsync(text);

        protected virtual async Task SetTextAndUpdateValueAsync(string? text, bool updateValue = true)
        {
            if (ReadText == text)
            {
                return;
            }

            _validated = false;

            if (!string.IsNullOrEmpty(text))
            {
                Touched = true;
            }

            await _textState.SetValueAsync(text);
            if (updateValue)
            {
                await UpdateValuePropertyAsync(false);
            }
        }

        private async Task OnTextParameterChangedAsync(ParameterChangedEventArgs<string?> arg)
        {
            _validated = false;

            if (!string.IsNullOrEmpty(arg.Value))
            {
                Touched = true;
            }

            // When Text changes from parent, update Value from Text using UpdateValuePropertyAsync
            // But only if Value is not also being set in the same parameter update
            // Check ParameterView to see if Value is also present
            if (!arg.ParameterView.Contains<T?>(nameof(Value)))
            {
                await UpdateValuePropertyAsync(updateText: false);
            }
        }

        private async Task UpdateInputIdStateAsync()
        {
            if (_inputIdState.Value is not null)
            {
                return;
            }

            if (_userAttributesId is not null)
            {
                await _inputIdState.SetValueAsync(_userAttributesId);
                return;
            }

            await _inputIdState.SetValueAsync(_componentId);
        }
    }
}

