        private Task OnInputOrOnChangeAsync(string? input) => Immediate ? OnInput(input) : OnChange(input);

        protected async Task OnInput(string? args)
        {
            _isFocused = true;
            _internalText = args;
            await OnInternalInputChanged.InvokeAsync(args);
