                .Add(x => x.Label, null)
                .Add(x => x.ToStringFunc, new Func<string?, string?>(x => x == "item2" ? "VERY LONG ITEM 2" : null)));

            // item1 -> null -> "Item 1 Rendered" (15 chars)
            // item2 -> "VERY LONG ITEM 2" (16 chars)

