private async Task OnFocusOutAsync()
{
    if (_openState.Value)
    {
        // when the menu is open we immediately get back the focus if we lose it (i.e. because of checkboxes in multi-select)
        // otherwise we can't receive key strokes any longer
        await FocusAsync();
    }
    else
    {
        // When focus leaves the select and the menu is closed, trigger validation.
        // This ensures that validation errors (e.g., Required) are shown when tabbing out
        // of an empty select, similar to how MudTextField handles blur events.
        Touched = true;
        await BeginValidateAsync();
    }
}

private Task SelectNextItem() => SelectAdjacentItem(+1);

